import {
  hasOwn,
  isNumberNaN,
  isUndefined,
  minErr,
} from "../../shared/utils.ts";
import { REGEX_STRING_REGEXP } from "./../attrs/attrs.ts";
import { startingTag } from "../../shared/dom.ts";
import { $injectTokens as $t } from "../../injection-tokens.ts";

type ValidatingNgModelController = ng.NgModelController & {
  $validators: Record<string, (modelValue: any, viewValue: any) => boolean>;
};

/**
 *
 * @param {string} ngRequired AngularTS expression. If it evaluates to `true`, it sets the
 *                                `required` attribute to the element and adds the `required`
 *                                {@link ngModel.NgModelController#$validators `validator`}.
 *
 *
 * ngRequired adds the required {@link ngModel.NgModelController#$validators `validator`} to {@link ngModel `ngModel`}.
 * It is most often used for {@link input `input`} and {@link select `select`} controls, but can also be
 * applied to custom controls.
 *
 * The directive sets the `required` attribute on the element if the AngularTS expression inside
 * `ngRequired` evaluates to true. A special directive for setting `required` is necessary because we
 * cannot use interpolation inside `required`. See the {@link guide/interpolation interpolation guide}
 * for more info.
 *
 * The validator will set the `required` error key to true if the `required` attribute is set and
 * calling {@link ngModel.NgModelController#$isEmpty `NgModelController.$isEmpty`} with the
 * {@link ngModel.NgModelController#$viewValue `ngModel.$viewValue`} returns `true`. For example, the
 * `$isEmpty()` implementation for `input[text]` checks the length of the `$viewValue`. When developing
 * custom controls, `$isEmpty()` can be overwritten to account for a $viewValue that is not string-based.
 *
 */
export const requiredDirective: [
  string,
  ($parse: ng.ParseService) => ng.Directive<any>,
] = [
  $t._parse,
  /**
   * @param {import("../../core/parse/interface.ts").ParseService} $parse
   * @returns {ng.Directive}
   */
  ($parse: ng.ParseService) => ({
    restrict: "A",
    require: "?ngModel",
    link:
      /**
       * @param {ng.Scope} scope
       * @param {Element} _elm
       * @param {ng.Attributes} attr
       * @param {ng.NgModelController} ctrl
       * @returns
       */
      (
        scope: ng.Scope,
        _elm: Element,
        attr: ng.Attributes,
        ctrl?: ValidatingNgModelController,
      ) => {
        if (!ctrl) return;
        // For boolean attributes like required, presence means true
        let value =
          hasOwn(attr, "required") ||
          (attr.ngRequired && $parse(attr.ngRequired)(scope));

        if (!attr.ngRequired) {
          // force truthy in case we are on non input element
          // (input elements do this automatically for boolean attributes like required)
          attr.required = "true";
        }

        ctrl.$validators.required = (_modelValue: any, viewValue: any) => {
          return !value || !ctrl.$isEmpty(viewValue);
        };

        attr.$observe("required", (newVal?: any) => {
          if (value !== newVal) {
            value = newVal;
            ctrl.$validate();
          }
        });
      },
  }),
];

/**
 * @param {String|RegExp} ngPattern AngularTS expression that must evaluate to a `RegExp` or a `String`
 *                                      parsable into a `RegExp`, or a `RegExp` literal. See above for
 *                                      more details.
 *
 *
 *
 * ngPattern adds the pattern {@link ngModel.NgModelController#$validators `validator`} to {@link ngModel `ngModel`}.
 * It is most often used for text-based {@link input `input`} controls, but can also be applied to custom text-based controls.
 *
 * The validator sets the `pattern` error key if the {@link ngModel.NgModelController#$viewValue `ngModel.$viewValue`}
 * does not match a RegExp which is obtained from the `ngPattern` attribute value:
 * - the value is an AngularTS expression:
 *   - If the expression evaluates to a RegExp object, then this is used directly.
 *   - If the expression evaluates to a string, then it will be converted to a RegExp after wrapping it
 *     in `^` and `$` characters. For instance, `"abc"` will be converted to `new RegExp('^abc$')`.
 * - If the value is a RegExp literal, e.g. `ngPattern="/^\d+$/"`, it is used directly.
 *
 * <div class="alert alert-info">
 * **Note:** Avoid using the `g` flag on the RegExp, as it will cause each successive search to
 * start at the index of the last search's match, thus not taking the whole input value into
 * account.
 * </div>
 *
 * <div class="alert alert-info">
 * **Note:** This directive is also added when the plain `pattern` attribute is used, with two
 * differences:
 * <ol>
 *   <li>
 *     `ngPattern` does not set the `pattern` attribute and therefore HTML5 constraint validation is
 *     not available.
 *   </li>
 *   <li>
 *     The `ngPattern` attribute must be an expression, while the `pattern` value must be
 *     interpolated.
 *   </li>
 * </ol>
 * </div>
 */
export const patternDirective: [
  string,
  ($parse: ng.ParseService) => ng.Directive<any>,
] = [
  $t._parse,
  /**
   * @param {ng.ParseService} $parse
   * @returns {ng.Directive}
   */
  ($parse: ng.ParseService) => ({
    restrict: "A",
    require: "?ngModel",
    compile: (_Elm: Element, tAttr: ng.Attributes) => {
      /**
       * @type {string}
       */
      let patternExp = "";

      /**
       * @type {(() => any) | ((arg0: ng.Scope) => string)}
       */
      let parseFn: (() => any) | ((scope: ng.Scope) => string) | undefined;

      if (tAttr.ngPattern) {
        patternExp = tAttr.ngPattern;

        // ngPattern might be a scope expression, or an inlined regex, which is not parsable.
        // We get value of the attribute here, so we can compare the old and the new value
        // in the observer to avoid unnecessary validations
        if (
          tAttr.ngPattern.charAt(0) === "/" &&
          REGEX_STRING_REGEXP.test(tAttr.ngPattern)
        ) {
          parseFn = function () {
            return tAttr.ngPattern;
          };
        } else {
          parseFn = tAttr.ngPattern && $parse(tAttr.ngPattern);
        }
      }

      return function (
        scope: ng.Scope,
        elm: Element | Node,
        attr: ng.Attributes,
        ctrl?: ValidatingNgModelController,
      ) {
        if (!ctrl) return;
        let attrVal = attr.pattern;

        if (attr.ngPattern) {
          attrVal = parseFn?.(scope);
        } else {
          patternExp = attr.pattern;
        }
        let regexp = attrVal && parsePatternAttr(attrVal, patternExp, elm);

        attr.$observe("pattern", (newVal?: any) => {
          const oldRegexp = regexp;

          regexp = newVal && parsePatternAttr(newVal, patternExp, elm);

          if (
            (oldRegexp && oldRegexp.toString()) !==
            (regexp && regexp.toString())
          ) {
            ctrl.$validate();
          }
        });

        ctrl.$validators.pattern = (_modelValue: any, viewValue: any) => {
          // HTML5 pattern constraint validates the input value, so we validate the viewValue
          return (
            ctrl.$isEmpty(viewValue) ||
            isUndefined(regexp) ||
            /** @type {RegExp} */ regexp.test(viewValue)
          );
        };
      };
    },
  }),
];

/**
 * @param {string} ngMaxlength AngularTS expression that must evaluate to a `Number` or `String`
 *                                 parsable into a `Number`. Used as value for the `maxlength`
 *                                 {@link ngModel.NgModelController#$validators validator}.
 *
 *
 *
 * ngMaxlength adds the maxlength {@link ngModel.NgModelController#$validators `validator`} to {@link ngModel `ngModel`}.
 * It is most often used for text-based {@link input `input`} controls, but can also be applied to custom text-based controls.
 *
 * The validator sets the `maxlength` error key if the {@link ngModel.NgModelController#$viewValue `ngModel.$viewValue`}
 * is longer than the integer obtained by evaluating the AngularTS expression given in the
 * `ngMaxlength` attribute value.
 *
 * <div class="alert alert-info">
 * **Note:** This directive is also added when the plain `maxlength` attribute is used, with two
 * differences:
 * <ol>
 *   <li>
 *     `ngMaxlength` does not set the `maxlength` attribute and therefore HTML5 constraint
 *     validation is not available.
 *   </li>
 *   <li>
 *     The `ngMaxlength` attribute must be an expression, while the `maxlength` value must be
 *     interpolated.
 *   </li>
 * </ol>
 * </div>
 *
 */
export const maxlengthDirective: [
  string,
  ($parse: ng.ParseService) => ng.Directive<any>,
] = [
  $t._parse,
  /**
   * @param {ng.ParseService} $parse
   * @returns {ng.Directive}
   */
  ($parse: ng.ParseService) => ({
    restrict: "A",
    require: "?ngModel",
    link:
      /**
       * @param {ng.Scope} scope
       * @param {Element} _elm
       * @param {ng.Attributes} attr
       * @param {ng.NgModelController} ctrl
       * @returns
       */
      (
        scope: ng.Scope,
        _elm: Element,
        attr: ng.Attributes,
        ctrl?: ValidatingNgModelController,
      ) => {
        if (!ctrl) return;

        let maxlength =
          attr.maxlength ||
          (attr.ngMaxlength && $parse(attr.ngMaxlength)(scope));

        let maxlengthParsed = parseLength(maxlength);

        attr.$observe("maxlength", (value?: any) => {
          if (maxlength !== value) {
            maxlengthParsed = parseLength(value);
            maxlength = value;
            ctrl.$validate();
          }
        });
        ctrl.$validators.maxlength = function (
          _modelValue: any,
          viewValue: any,
        ) {
          return (
            maxlengthParsed < 0 ||
            ctrl.$isEmpty(viewValue) ||
            viewValue.length <= maxlengthParsed
          );
        };
      },
  }),
];

/**
 *
 * @param {string} ngMinlength AngularTS expression that must evaluate to a `Number` or `String`
 *                                 parsable into a `Number`. Used as value for the `minlength`
 *                                 {@link ngModel.NgModelController#$validators validator}.
 *
 *
 *
 * ngMinlength adds the minlength {@link ngModel.NgModelController#$validators `validator`} to {@link ngModel `ngModel`}.
 * It is most often used for text-based {@link input `input`} controls, but can also be applied to custom text-based controls.
 *
 * The validator sets the `minlength` error key if the {@link ngModel.NgModelController#$viewValue `ngModel.$viewValue`}
 * is shorter than the integer obtained by evaluating the AngularTS expression given in the
 * `ngMinlength` attribute value.
 *
 * <div class="alert alert-info">
 * **Note:** This directive is also added when the plain `minlength` attribute is used, with two
 * differences:
 * <ol>
 *   <li>
 *     `ngMinlength` does not set the `minlength` attribute and therefore HTML5 constraint
 *     validation is not available.
 *   </li>
 *   <li>
 *     The `ngMinlength` value must be an expression, while the `minlength` value must be
 *     interpolated.
 *   </li>
 * </ol>
 * </div>
 *
 */
export const minlengthDirective: [
  string,
  ($parse: ng.ParseService) => ng.Directive<any>,
] = [
  $t._parse,
  /** @param {ng.ParseService} $parse @return {ng.Directive} */ (
    $parse: ng.ParseService,
  ) => ({
    restrict: "A",
    require: "?ngModel",
    link(
      scope: ng.Scope,
      _elm: Element,
      attr: ng.Attributes,
      ctrl?: ValidatingNgModelController,
    ) {
      if (!ctrl) return;

      let minlength =
        attr.minlength || (attr.ngMinlength && $parse(attr.ngMinlength)(scope));

      let minlengthParsed = parseLength(minlength) || -1;

      attr.$observe("minlength", (value?: any) => {
        if (minlength !== value) {
          minlengthParsed = parseLength(value) || -1;
          minlength = value;
          ctrl.$validate();
        }
      });
      ctrl.$validators.minlength = function (
        modelValue: any,
        viewValue: string | any[],
      ) {
        void modelValue;
        return ctrl.$isEmpty(viewValue) || viewValue.length >= minlengthParsed;
      };
    },
  }),
];

/**
 * @param {string | RegExp} input
 * @param {string} patternExp
 * @param {Element | Node} elm
 * @returns {RegExp}
 */
function parsePatternAttr(
  input: string | RegExp,
  patternExp: string,
  elm: Element | Node,
): RegExp {
  /** @type {RegExp | string} */
  let regex = input;

  if (typeof regex === "string") {
    const match = regex.match(/^\/(.*)\/([gimsuy]*)$/);

    regex = match ? new RegExp(match[1], match[2]) : new RegExp(`^${regex}$`);
  }

  if (typeof regex.test !== "function") {
    throw minErr("ngPattern")(
      "noregexp",
      "Expected {0} to be a RegExp but was {1}. Element: {2}",
      patternExp,
      regex,
      startingTag(elm),
    );
  }

  return regex;
}

/**
 * @param {string} val
 */
function parseLength(val: any): number {
  const intVal = parseInt(val, 10);

  return isNumberNaN(intVal) ? -1 : intVal;
}
